fn solve(n: i64, m: i64, k: i64) -> i64 {
    if k == 0 {
        return n * m;
    }

    if k >= (std::cmp::min(n, m) as i64) / 2 {
        return 1;
    }

    let mut count = 0;
    let mut covered = std::collections::HashSet::new();

    for r in 0..n {
        for c in 0..m {
            if covered.contains(&(r, c)) {
                continue;
            }

            // Place a sensor at (r, c)
            count += 1;

            // Mark all cells covered by this sensor
            for i in std::cmp::max(0, r - k)..=std::cmp::min(n - 1, r + k) {
                for j in std::cmp::max(0, c - k)..=std::cmp::min(m - 1, c + k) {
                    covered.insert((i, j));
                }
            }
        }
    }

    count
}
